SELECT ItemID as itemId, Version as revNo, DocumentNo as docNo, Identifier as identifier FROM XBOLTADM.TI_ITEM_IF WHERE DocumentNo = #{docNo}
AND Version = #{version}
AND Identifier LIKE #{identifier} + '%'

  		SELECT
			DISTINCT(ItemID) as itemId
			FROM XBOLTADM.TI_ITEM_IF
			WHERE DocumentNo = #{docNo}
			AND Version = #{version}

mapper.update:
UPDATE XBOLTADM.TB_ITEM 
SET Creator = #{MemberID}
	,LastUser = #{MemberID}
	,CompanyID = #{CompanyID}
	,OwnerTeamID = #{TeamID}
	,AuthorID = #{MemberID}
WHERE ItemID = #{itemId}

mapper.select:
		SELECT LovCode
  		FROM XBOLTADM.TB_ATTR_TYPE_LOV
  		WHERE 1 =1 
  			
  				
  					AND AttrTypeCode = #{attrTypeCode}
				
				
  					AND AttrTypeCode LIKE 'ZAT%'
				
			
  			AND Value = #{value}
  			AND LanguageID = #{languageID}

		SELECT Value
  		FROM XBOLTADM.TB_ATTR_TYPE_LOV
  		WHERE 1 =1 				
  			AND AttrTypeCode LIKE 'ZAT%'
  			AND LovCode = #{lovCode}
  			AND LanguageID = #{languageID}

		SELECT LovCode as lovCode
  		FROM XBOLTADM.TB_ATTR_TYPE_LOV
  		WHERE  AttrTypeCode = #{lv3AttrTypeCode}
   			AND Value = #{docProc}

SELECT
	L3.ItemID
FROM XBOLTADM.TB_ITEM_ATTR L3
LEFT JOIN XBOLTADM.TB_ITEM L2ST ON 
	L2ST.CategoryCode = #{categoryCode}  
	AND L2ST.ToItemID = L3.ItemID
LEFT JOIN XBOLTADM.TB_ITEM_ATTR L2 ON 
	L2.AttrTypeCode = #{attrTypeCode}
	AND L2.ClassCode = #{lv2ClassCode}
	AND L2.LanguageID = #{languageId}
	AND L2.PlainText = #{docTyp}
	AND L2.ItemID = L2ST.FromItemID
LEFT JOIN XBOLTADM.TB_ITEM L1ST ON 
	L2ST.CategoryCode = #{categoryCode} 
	AND L1ST.ToItemID = L2.ItemID
LEFT JOIN XBOLTADM.TB_ITEM_ATTR L1 ON 
	L1.AttrTypeCode = #{attrTypeCode}
	AND L1.ClassCode = #{lv1ClassCode}
	AND L1.LanguageID = #{languageId}
	AND L1.PlainText = #{docArea}
	AND L1.ItemID = L1ST.FromItemID
WHERE L3.AttrTypeCode = #{attrTypeCode}
	AND L3.ClassCode = #{lv3ClassCode}
	AND L3.LanguageID = #{languageId}
	AND L3.PlainText = #{docProc}
	AND L2.ItemID IS NOT NULL 
	AND L1.ItemID IS NOT NULL

mapper.insert:
 		INSERT INTO
 			XBOLTADM.TB_CHANGE_SET(
 			ChangeSetID
			
 			, Version
			
 			, ProjectID
            , PJTCategory
            , ItemID
            , ItemClassCode
            
            , ItemTypeCode
            , AuthorID
            , AuthorName
            , AuthorTeamID
            , CompanyID
            
            , Description
            , ChangeType
            , Reason
            , Status
 			, CreationTime
 			
 			, Approver
 			, ToItemID
 			, FromItemID
 			, CheckInOption
 			
 			, SRID
 			
 			
 			, CRID
 			
 			, ApproveDate
 			, CompletionDT
 		)VALUES(
			#{ChangeSetID}
			
			, #{version}
			
			, #{ProjectID}
			, #{PJTCategory}
			, #{ItemID}
			, #{ItemClassCode}
			
			, #{ItemTypeCode}
			, #{AuthorID}
			, N''+#{AuthorName}
			, #{AuthorTeamID}
			, #{CompanyID}
			
			, #{Description}
			, #{ChangeType}
			, #{Reason}
			, #{Status}
			, getdate()
			
			, #{Approver}
			, #{ToItemID}
			, #{FromItemID}
			, #{checkInOption}
			
 			, #{SRID}
 			
 			
 			, #{SCRID}
 			
			, getdate()
			, getdate()
		)
